mapper.delete:
DELETE FROM EVA_POOL_DISQ_UNIV
WHERE
    PERIOD_DIV_CD = #{periodDivCd}
    AND EVA_YEAR = #{evaYear}
    AND POOL_CD = #{poolCd}
    AND USR_ID = #{usrId}

mapper.update:
UPDATE EVA_POOL_APPL
SET 
    DISQ_YN_1 = #{disq1Univ},
    DISQ_YN_2 = #{disq2Univ},
    LAST_CHNRG_ID = #{usrId},
    LAST_CHG_DT = SYSDATE
WHERE 
    PERIOD_DIV_CD = #{periodDivCd}
    AND EVA_YEAR = #{evaYear}
    AND POOL_CD = #{poolCd}
    AND USR_ID = #{usrId}

mapper.select:
SELECT ROW_NUMBER() OVER (ORDER BY UNIV_NM) R_NUM, UNIV_CD, UNIV_NM FROM EVA_UNIV
AND (UNIV_NM LIKE '%' || #{searchText} || '%') AND EVA_TARGET = #{evaTarget}
ORDER BY UNIV_NM
